CLASS_NAMES    = ["solder_bridge", "missing_component", "misalignment", "polarity_error", "good"]
GOOD_CLASSES   = ["good", "pass", "normal", "no-defect", "no_defect"]
DEFECT_CLASSES = ["solder_bridge", "missing_component", "misalignment", "polarity_error"]

DEFECT_COLORS = {
    "solder_bridge"    : (0,   0,   255),
    "missing_component": (255, 0,   0  ),
    "misalignment"     : (0,   165, 255),
    "polarity_error"   : (128, 0,   128),
    "short"            : (0,   0,   200),
    "open"             : (200, 100, 0  ),
    "spurious_copper"  : (0,   200, 200),
    "default"          : (255, 50,  50 ),
}

# ── HELPER FUNCTIONS ──────────────────────────
def safe_text(text):
    reps = {chr(8211):'-', chr(8212):'-', chr(8216):"'",
            chr(8217):"'", chr(8220):'"', chr(8221):'"'}
    for k,v in reps.items(): text = text.replace(k,v)
    return text.encode('latin-1', errors='replace').decode('latin-1')

def get_max_conf(det_json):
    try:
        dets = json.loads(det_json) if isinstance(det_json,str) else det_json
        dd = [d for d in dets if d.get('class','').lower() not in GOOD_CLASSES]
        return round(max(d.get('confidence',0) for d in dd),3) if dd else 0.0
    except: return 0.0

def get_defect_classes(det_json):
    try:
        dets = json.loads(det_json) if isinstance(det_json,str) else det_json
        cls  = [d.get('class','') for d in dets if d.get('class','').lower() not in GOOD_CLASSES]
        return ', '.join(set(cls)) if cls else 'none'
    except: return 'none'

def get_verdict_reason(verdict, max_conf):
    if verdict=='PASS':   return 'No defects detected above threshold'
    elif verdict=='FAIL': return f'Defect confidence {max_conf:.2f} >= 0.70 - board rejected'
    else:                 return f'Defect confidence {max_conf:.2f} between 0.45 and 0.69 - needs review'

def b64_to_pil(b64_str):
    try:
        if not b64_str: return None
        return Image.open(BytesIO(base64.b64decode(b64_str)))
    except: return None

def draw_defects(pil_img, defect_dets):
    img = cv2.cvtColor(np.array(pil_img.resize((640,640)).convert('RGB')), cv2.COLOR_RGB2BGR)
    for det in defect_dets:
        x1,y1,x2,y2 = map(int, det['bbox'])
        cls   = det['class']
        conf  = det['confidence']
        color = DEFECT_COLORS.get(cls, DEFECT_COLORS['default'])
        cv2.rectangle(img,(x1,y1),(x2,y2),color,2)
        label = f'{cls} {conf:.0%}'
        (tw,th),_ = cv2.getTextSize(label, cv2.FONT_HERSHEY_SIMPLEX, 0.5, 1)
        cv2.rectangle(img,(x1,y1-th-10),(x1+tw+6,y1),color,-1)
        cv2.putText(img,label,(x1+3,y1-4),cv2.FONT_HERSHEY_SIMPLEX,0.5,(255,255,255),1)
    return Image.fromarray(cv2.cvtColor(img,cv2.COLOR_BGR2RGB))

def call_inference_api(api_url, img_bytes, conf=0.45):
    try:
        resp = requests.post(
            f"{api_url.rstrip('/')}/inspect",
            files={'file':('image.jpg', img_bytes, 'image/jpeg')},
            params={'conf': conf},
            timeout=30
        )
        if resp.status_code == 200: return resp.json(), None
        return None, f'API error {resp.status_code}'
    except requests.exceptions.ConnectionError:
        return None, 'Cannot reach API - check URL or restart Colab server'
    except requests.exceptions.Timeout:
        return None, 'API timeout - Colab may be busy'
    except Exception as e:
        return None, str(e)

