df['max_conf']    = df['detections'].apply(get_max_conf)
df['defect_type'] = df['detections'].apply(get_defect_classes)
df['reason']      = df.apply(lambda r: get_verdict_reason(r['verdict'],r['max_conf']),axis=1)

