    if api_url:
        try:
            r = requests.get(
                f"{api_url.rstrip('/')}/health",
                headers={'ngrok-skip-browser-warning':'true'},
                timeout=8
            )
            if r.status_code == 200:
                info = r.json()
                st.success(f"API connected — Model: {info.get('model','YOLOv8m')} | Classes: {len(info.get('classes',[]))} | Status: ok")
            else:
                st.error(f'API responded with status {r.status_code}')
        except Exception as e:
            st.warning(f'Cannot reach API: {e}')
    else:
        st.info('Start the FastAPI server in Google Colab, then paste the ngrok URL above')

    st.markdown('---')
    st.markdown('#### Step 2 — Upload PCB Image')
    col_up, col_conf = st.columns([3,1])
    with col_up:
        uploaded_file = st.file_uploader('Choose a PCB image', type=['jpg','jpeg','png'])
    with col_conf:
        live_conf = st.slider('Confidence threshold', 0.1, 0.9, 0.45, 0.05, format='%.2f')

    if uploaded_file is not None:
        if not api_url:
            st.error('Please enter the Colab API URL in Step 1 above first')
            st.stop()
        pil_img   = Image.open(uploaded_file)
        img_bytes = uploaded_file.getvalue()
        with st.spinner('Running real YOLOv8 inference on GPU...'):
            result, err = call_inference_api(api_url, img_bytes, live_conf)
        if err:
            st.error(f'Inference failed: {err}')
            st.info('Check that Colab is still running and the URL is correct')
            st.stop()
        defect_dets = result.get('detections', [])
        verdict     = result.get('verdict', 'PASS')
        max_conf    = max((d['confidence'] for d in defect_dets), default=0.0)
        reason      = get_verdict_reason(verdict, max_conf)
        annotated   = draw_defects(pil_img, defect_dets)
        vcolor = {'PASS':'#22c55e','FAIL':'#ef4444','REVIEW':'#f59e0b'}[verdict]
        vemoji = {'PASS':'✅','FAIL':'❌','REVIEW':'🔶'}[verdict]
        st.markdown(
            f"<div style='background:{vcolor}22;border:2px solid {vcolor};"
            f"border-radius:12px;padding:16px 20px;margin:12px 0'>"
            f"<h2 style='color:{vcolor};margin:0'>{vemoji} {verdict}</h2>"
            f"<p style='margin:6px 0 0;color:#555'>{reason}</p>"
            f"<p style='margin:4px 0 0;color:#888;font-size:13px'>"
            f"Defects: {len(defect_dets)} | Conf: {max_conf:.3f} | Real YOLOv8 GPU</p>"
            f"</div>", unsafe_allow_html=True)
        ic1, ic2 = st.columns(2)
        with ic1:
            st.markdown('**Original Image**')
            st.image(pil_img, use_column_width=True, caption=f'Uploaded: {uploaded_file.name}')
        with ic2:
            st.markdown('**Defects Only — Real YOLOv8 Output**')
            st.image(annotated, use_column_width=True, caption='Only defective components highlighted')
        if defect_dets:
            st.markdown('**Detected Defects**')
            det_rows = [{'No':i+1,'Defect Class':d['class'],'Confidence':f"{d['confidence']:.3f}",'Severity':'HIGH' if d['confidence']>=0.70 else 'MEDIUM'} for i,d in enumerate(defect_dets)]
            det_df = pd.DataFrame(det_rows)
            def color_sev(val): return 'color:#ef4444;font-weight:bold' if val=='HIGH' else 'color:#f59e0b;font-weight:bold'
            st.dataframe(det_df.style.map(color_sev,subset=['Severity']), use_container_width=True, hide_index=True)
            from collections import Counter
            counts = Counter(d['class'] for d in defect_dets)
            scols  = st.columns(max(len(counts),1))
            for i,(cls,cnt) in enumerate(counts.items()): scols[i].metric(cls, cnt)
        else:
            st.success('No defects detected — board passes inspection')
    else:
        st.divider()
        st.subheader('Sample Results from Trained Model')
        sample_recs = [r for r in RAW_DATA if IMAGE_DATA.get(r['image'],{}).get('annotated')][:6]
        if sample_recs:
            cols = st.columns(3)
            for i,rec in enumerate(sample_recs):
                fname=rec['image']; verdict=rec['verdict']
                ann_img=b64_to_pil(IMAGE_DATA.get(fname,{}).get('annotated',''))
                vcolor={'PASS':'green','FAIL':'red','REVIEW':'orange'}.get(verdict,'gray')
                vemoji={'PASS':'✅','FAIL':'❌','REVIEW':'🔶'}.get(verdict,'')
                with cols[i%3]:
                    if ann_img: st.image(ann_img, use_column_width=True)
                    st.markdown(f"<p style='text-align:center;color:{vcolor};font-weight:bold'>{vemoji} {verdict}</p>",unsafe_allow_html=True)
                    st.caption(fname)

